#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, C;
        scanf("%d %d", &N, &C);
        int* arr = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            arr[i] = 1;
        }
        long long fact = 1;
        for (int i = 1; i <= N; i++) {
            fact *= i;
        }
        if (fact < C) {
            printf("-1\n");
        } else {
            for (int i = N - 1; i >= 0; i--) {
                while (fact > C && arr[i] < N) {
                    fact /= (arr[i] + 1);
                    arr[i]++;
                    fact *= arr[i];
                }
            }
            for (int i = 0; i < N; i++) {
                printf("%d ", arr[i]);
            }
            printf("\n");
        }
        free(arr);
    }
    return 0;
}

