        while (T-- > 0) {
            int N = sc.nextInt();
            long C = sc.nextLong();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = 1;
            }
            long fact = 1;
            for (int i = 1; i <= N; i++) {
                fact *= i;
            }
            if (fact < C) {
                System.out.println("-1");
            } else {
                for (int i = N - 1; i >= 0; i--) {
                    while (fact > C && arr[i] < N) {
                        fact /= (arr[i] + 1);
                        arr[i]++;
                        fact *= arr[i];
                    }
                }
                for (int i = 0; i < N; i++) {
                    System.out.print(arr[i] + " ");
                }
                System.out.println();
            }
